const SOPS = {"SOP-01": {"nom": "Qualification initiale alarme", "objectif": "Identifier et qualifier l'alarme dans Lightsoft + Vizee, évaluer l'impact opérationnel, horodater l'incident.", "steps": ["Ouvrir Lightsoft ET Vizee simultanément", "Identifier couleur NE : Bleu/gris → supervision seule · Rouge → trafic impacté", "Compter alarmes simultanées : 1 isolée vs avalanche = diagnostic différent", "Croiser avec journal des opérations : travaux en cours ? maintenance ?", "Horodater l'alarme (heure de début)", "⚠ NE bleu/gris ≠ perte de trafic — ne pas escalader avant confirmation"]}, "SOP-02": {"nom": "Vérification rack OOB", "objectif": "Contrôler l'infrastructure OOB : alimentation, switch, firewall Vizee, câblage, caméra, Lugos.", "steps": ["Vérifier l'alimentation de la baie OOB (2 alimentations A+B)", "Vérifier le switch OOB : voyants actifs, connexions cuivre", "Vérifier le firewall Vizee : état, derniers logs d'accès", "Vérifier câblage de gestion : tous les NEs accessibles", "Vérifier la caméra : flux visible sur Vizee", "Vérifier l'état Lugos : services actifs, logs récents"]}, "SOP-03": {"nom": "Vérification supervision Lightsoft", "objectif": "Vérifier la session Lightsoft et l'accessibilité des NEs via Radius/STMS.", "steps": ["Vérifier que Lightsoft est connecté au STMS (pas de croix rouge)", "Vérifier la session Radius : certificat, date d'expiration", "Tenter d'accéder à un NE en difficulté depuis Lightsoft", "Si session expirée : relancer la session STMS", "Vérifier les ports 830/22 ouverts entre OOB et NEs", "Si inaccessible : basculer sur session de secours STMS"]}, "SOP-04": {"nom": "Vérification bascule OLP + OSNR", "objectif": "Tester la bascule OLP et contrôler les niveaux OSNR sur les 2 ports optiques.", "steps": ["Ouvrir Trail List → icône S → vérifier chemin actif", "Confirmer bascule OLP : lien HS = rouge, lien en service = vert", "Vérifier OSNR sur les 2 ports de réception des liens opérateurs", "Vérifier état port OSC port 0 carte OADVLF (SFP OSC)", "Si bascule OLP active → confirmer stabilité du lien restant", "Surveiller évolution OSNR dans les 15 minutes suivantes"]}, "SOP-05": {"nom": "Vérification physique rack OTN", "objectif": "Vérification physique sur site : voyants cartes, alimentation, ventilation, identification par photo.", "steps": ["Accéder au rack physique via Lugos ou déplacement terrain", "Vérifier voyants de la carte incriminée : vert=OK, rouge=alarme", "Vérifier l'alimentation redondante (A+B) : LEDs vertes", "Vérifier la ventilation : pas de blocage, température normale", "Photographier l'état du rack (référence pour Ribbon/NOC)", "Identifier carte par slot et numéro de série (Vizee)"]}, "SOP-06": {"nom": "Vérification carte RCP", "objectif": "Basculer la carte RCP A→B et vérifier câblage cuivre + état File System.", "steps": ["Identifier la carte RCP active (A ou B) depuis Lightsoft", "Basculer RCP A → B (ou B → A) depuis l'interface Lightsoft", "Attendre 2-3 min et observer la stabilisation des alarmes", "Vérifier le câblage cuivre RJ45 management (non débranché)", "Vérifier l'état du File System de la carte RCP", "Si échec bascule : escalader vers Ribbon Support"]}, "SOP-07": {"nom": "Vérification port SFP + jarretière", "objectif": "Inspecter le port SFP et la jarretière optique : état, propreté, alignement, côté opérateur.", "steps": ["Vérifier état du SFP sur Lightsoft : valeur signal, erreurs", "Si SFP en défaut → préparer remplacement (après accord manager)", "Vérifier jarretière : bien connectée, non abîmée visuellement", "Inspecter jarretière à la caméra d'inspection fibre", "Si salissure → nettoyage ou remplacement jarretière", "Vérifier aussi côté équipement opérateur si accès disponible"]}, "SOP-08": {"nom": "Ouverture ticket opérateur", "objectif": "Ouvrir un ticket auprès de l'opérateur tiers (Cogent, EuNetwork) et suivre la résolution.", "steps": ["Identifier l'opérateur tiers concerné (Cogent, EuNetwork, autre)", "Ouvrir ticket via portail opérateur avec : heure alarme, description, impact", "Fournir les données PM (OPR/OPT) mesurées", "Obtenir un numéro de ticket et l'enregistrer dans le journal", "Relancer toutes les 30 min si pas de réponse", "Escalader vers account manager si dépassement SLA"]}, "SOP-09": {"nom": "Ouverture ticket Lugos", "objectif": "Ouvrir un ticket Lugos pour intervention OOB ou câblage terrain.", "steps": ["Accéder au portail Lugos (accès VPN requis)", "Créer un ticket avec : numéro de rack, carte, description précise", "Joindre photo du rack si disponible", "Sélectionner priorité selon criticité incident", "Suivre le ticket jusqu'à accusé de réception Lugos", "Confirmer créneau d'intervention si site physique requis"]}, "SOP-10": {"nom": "Ouverture ticket Ribbon + RMA", "objectif": "Ouvrir un ticket Ribbon avec numéro de série (Vizee) et initier le processus RMA.", "steps": ["Récupérer le numéro de série de la carte depuis Vizee", "Accéder au portail support.ribbon.com", "Ouvrir un cas avec : S/N, firmware, description panne, logs exportés", "Initier le processus RMA si remplacement matériel nécessaire", "Obtenir ETA livraison et procédure de remplacement", "Conserver la carte défectueuse emballée pour retour constructeur"]}, "SOP-11": {"nom": "Communication incident", "objectif": "Informer sites, manager, Ribbon ; envoyer mail d'incident et mails de suivi toutes les 30 min jusqu'à clôture.", "steps": ["Informer le manager de l'alarme en cours (criticité + impact)", "Si CRITIQUE ou >30 min : envoyer rapport intermédiaire par email", "Mettre à jour le journal des incidents", "Notifier résolution avec heure de fin et cause racine identifiée"]}, "SOP-12": {"nom": "Lecture PM Counters Lightsoft", "objectif": "Lire les PM Counters Lightsoft (OPR/OPT, FEC, BER) pour analyse qualité de lien.", "steps": ["Ouvrir Lightsoft → onglet Performance Monitoring", "Sélectionner le NE et la période 15 min la plus récente", "Relever OPR (puissance reçue, dBm) — normal: -10 à -20 dBm", "Relever OPT (puissance émise, dBm)", "Relever FEC (Forward Error Correction) et BER (Bit Error Rate)", "Comparer avec valeurs de référence de la baseline"]}, "SOP-13": {"nom": "Validation post-résolution — Test Viavi OTU2 (RFC 2544)", "objectif": "Valider la conformité du lien restauré par test RFC 2544 (2 Viavi OTU2) aux 2 extrémités.", "steps": ["Positionner 2 Viavi OTU2 aux 2 extrémités du lien (TH2 + LF ou TH3)", "Configurer test RFC 2544 : trafic 10G, frames 64B/512B/1518B", "Lancer le test (durée : 5-10 min minimum)", "Vérifier : 0% frame loss, latence < 1ms, jitter < 100µs", "Imprimer ou sauvegarder le rapport de test (PDF)", "Valider la remise en service avec le manager NOC"]}, "SOP-14": {"nom": "SMTP / Email relay Vizee HS", "objectif": "Rétablir le service d'envoi d'emails d'alarme depuis Vizee quand le relay SMTP est hors service.", "steps": ["Vérifier les logs du service SMTP relay dans Vizee", "Tester l'envoi d'un email de test depuis l'interface Vizee", "Vérifier la configuration MX/DNS du domaine d'envoi", "Vérifier les credentials SMTP (expiration, rotation de mot de passe)", "Si relay tiers (SendGrid, etc.) : vérifier quota et statut du compte", "Redémarrer le service d'alerte si configuration OK mais service bloqué"]}};
const PHASE_MAP = {"SOP-01": 1, "SOP-02": 2, "SOP-03": 2, "SOP-04": 2, "SOP-05": 2, "SOP-06": 2, "SOP-07": 2, "SOP-12": 2, "SOP-08": 3, "SOP-09": 3, "SOP-10": 3, "SOP-11": 4, "SOP-13": 5, "SOP-14": 2};
const PHASES = {"1": {"nom": "Qualification", "desc": "Qualifier l'alarme, évaluer l'impact opérationnel et horodater l'incident.", "color": "#1a3a5c"}, "2": {"nom": "Diagnostic & Intervention", "desc": "Identifier la cause racine par des vérifications techniques ciblées sur les équipements concernés.", "color": "#2c5f8a"}, "3": {"nom": "Escalade / RMA", "desc": "Ouvrir les tickets opérateur/constructeur et initier le processus RMA si remplacement matériel nécessaire.", "color": "#3a5a8a"}, "4": {"nom": "Communication", "desc": "Informer toutes les parties prenantes et assurer le suivi jusqu'à clôture.", "color": "#4a4a8a"}, "5": {"nom": "Validation", "desc": "Valider la conformité du lien restauré par test RFC 2544 (Viavi OTU2) avant remise en service définitive.", "color": "#2e7d32"}};

const body = $input.first().json.body || $input.first().json;
const {
  incident_id, incident_type, sous_type, criticite, sops,
  site, equipment, technicien, date_intervention, heure_debut,
  symptome, impact, cause_probable,
  alarme_lightsoft, alarme_vizee,
  contexte_kb, cas_reels, reseau, categorie
} = body;

const sopsArr = typeof sops === 'string'
  ? sops.split(',').map(s => s.trim()).filter(Boolean)
  : (Array.isArray(sops) ? sops : []);

// Build phase groups
const phaseGroups = {};
for (const s of sopsArr) {
  const ph = PHASE_MAP[s] || 2;
  if (!phaseGroups[ph]) phaseGroups[ph] = [];
  phaseGroups[ph].push(s);
}
const phaseNums = Object.keys(phaseGroups).map(Number).sort();

// Criticité CSS class
const critClass = criticite === 'MINEUR' ? 'crit-mineur'
  : criticite === 'MAJEUR' ? 'crit-majeur'
  : criticite === 'CRITIQUE' ? 'crit-critique' : '';
const critValueClass = 'crit-value-' + (critClass.replace('crit-', '') || 'majeur');

// Date/time
const dateStr = date_intervention || '____________________';
const heureStr = heure_debut || '________';
const techStr = technicien || '________________________';
const genTime = new Date().toISOString().replace('T', ' ').slice(0, 16) + ' UTC';
const docId = 'MOP-' + (incident_id || 'XXX');
const filename = 'mop-' + (incident_id || 'xxx').toLowerCase() + '.pdf';
const docxFilename = 'mop-' + (incident_id || 'xxx').toLowerCase() + '.docx';

// Helper: escape HTML
function esc(s) {
  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

// Criticité banner
const critBannerHtml = `<div class="crit-banner ${critClass}">
  <div><div class="crit-label">Criticité</div><div class="${critValueClass}">${esc(criticite || 'N/A')}</div></div>
  <div style="flex:1"><div class="crit-label">Catégorie</div><div class="crit-cat">${esc(categorie || incident_type || 'N/A')} — ${esc(sous_type || 'N/A')}</div></div>
  <div><div class="crit-label">Réseau</div><div class="crit-cat">${esc(reseau || 'OTN')}</div></div>
  <div><div class="crit-label">SOPs applicables</div><div class="crit-cat">${sopsArr.length} SOP(s) en ${phaseNums.length} phase(s)</div></div>
</div>`;

// Meta grid
const metaHtml = `<div class="meta-grid">
  <div class="meta-card">
    <div class="meta-card-title">Identification de l'incident</div>
    <div class="meta-row"><span class="meta-key">Référence :</span><span class="meta-val">${docId}</span></div>
    <div class="meta-row"><span class="meta-key">Catégorie :</span><span class="meta-val">${esc(categorie || incident_type || 'N/A')}</span></div>
    <div class="meta-row"><span class="meta-key">Sous-type :</span><span class="meta-val">${esc(sous_type || 'N/A')}</span></div>
    <div class="meta-row"><span class="meta-key">Réseau :</span><span class="meta-val">${esc(reseau || 'OTN')}</span></div>
  </div>
  <div class="meta-card">
    <div class="meta-card-title">Intervention</div>
    <div class="meta-row"><span class="meta-key">Site :</span><span class="meta-val">${esc(site || 'N/A')}</span></div>
    <div class="meta-row"><span class="meta-key">Technicien :</span><span class="meta-val">${esc(techStr)}</span></div>
    <div class="meta-row"><span class="meta-key">Date :</span><span class="meta-val">${esc(dateStr)}</span></div>
    <div class="meta-row"><span class="meta-key">Heure début :</span><span class="meta-val">${esc(heureStr)}</span></div>
    <div class="meta-row"><span class="meta-key">Ticket :</span><span class="meta-val">________________________</span></div>
  </div>
</div>`;

// Description bloc
const descHtml = (symptome || impact || cause_probable) ? `<div class="meta-card" style="margin-bottom:16px">
  <div class="meta-card-title">Description de l'incident</div>
  ${symptome ? '<div class="meta-row"><span class="meta-key">Symptôme :</span><span class="meta-val">' + esc(symptome) + '</span></div>' : ''}
  ${impact ? '<div class="meta-row"><span class="meta-key">Impact opérationnel :</span><span class="meta-val">' + esc(impact) + '</span></div>' : ''}
  ${cause_probable ? '<div class="meta-row"><span class="meta-key">Cause probable :</span><span class="meta-val">' + esc(cause_probable) + '</span></div>' : ''}
</div>` : '';

// Alarm block
const alarmHtml = (alarme_lightsoft || alarme_vizee) ? `<div class="alarm-block">
  <div class="alarm-title">⚡ Alarmes de référence — Signatures attendues</div>
  ${alarme_lightsoft ? '<div class="alarm-row"><span class="alarm-system">Lightsoft :</span><span class="alarm-text">' + esc(alarme_lightsoft) + '</span></div>' : ''}
  ${alarme_vizee ? '<div class="alarm-row"><span class="alarm-system">Vizee :</span><span class="alarm-text">' + esc(alarme_vizee) + '</span></div>' : ''}
</div>` : '';

// Cas réels
const casHtml = cas_reels ? `<div class="section-block cas-block">
  <div class="section-title cas-title">📋 Cas réels observés (2021-2025)</div>
  <div class="cas-text">${esc(cas_reels).replace(/\n/g, '<br>')}</div>
</div>` : '';

// KB context
let kbHtml = '';
if (contexte_kb) {
  const chunks = typeof contexte_kb === 'string' ? JSON.parse(contexte_kb) : contexte_kb;
  if (Array.isArray(chunks) && chunks.length > 0) {
    const items = chunks.map(c => `<div class="kb-item">
      <div class="kb-source">📄 ${esc(c.filename || c.source || 'Source')} <span class="kb-score">[pertinence: ${(c.score || 0).toFixed(2)}]</span></div>
      <div class="kb-text">${esc((c.text || '').slice(0, 400))}</div>
    </div>`).join('');
    kbHtml = `<div class="section-block kb-block">
  <div class="section-title kb-title">📚 Base de connaissance — Contexte technique extrait</div>
  ${items}
</div>`;
  }
}

// Phases & SOPs
let phasesHtml = '';
for (const phNum of phaseNums) {
  const ph = PHASES[String(phNum)] || PHASES[phNum] || { nom: 'Phase ' + phNum, desc: '', color: '#2c5f8a' };
  const phSops = phaseGroups[phNum];
  const sopCards = phSops.map(s => {
    const info = SOPS[s] || { nom: s, objectif: '', steps: [] };
    const stepsHtml = (info.steps || []).map(st => '<li>' + esc(st) + '</li>').join('');
    return `<div class="sop-card">
      <div class="sop-header">
        <span class="sop-badge">${s}</span>
        <span class="sop-title">${esc(info.nom)}</span>
        <span class="sop-check">☐ Validé</span>
      </div>
      ${stepsHtml ? '<ol class="sop-steps">' + stepsHtml + '</ol>' : '<div style="font-size:9.5pt;color:#555;padding:4px 0">' + esc(info.objectif) + '</div>'}
      <div class="sop-note-row">
        <span class="note-label">Notes :</span>
        <span class="note-line">_____________________________________________________________</span>
      </div>
    </div>`;
  }).join('');
  phasesHtml += `<div class="phase-block">
  <div class="phase-header" style="background:${ph.color}">
    <span class="phase-num">Phase ${phNum}</span>
    <span class="phase-nom"> — ${ph.nom}</span>
  </div>
  <div class="phase-desc">${ph.desc}</div>
  ${sopCards}
</div>`;
}

const html = `<!DOCTYPE html>
